import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, LinearProgress } from '@mui/material';
import { ArrowUpward } from '@mui/icons-material';
import response from './response.json';

interface Playtime {
  totalHours: number;
  lastSession: string;
  averageSession: number;
}

interface Achievement {
  name: string;
  unlocked: boolean;
  dateUnlocked: string | null;
}

interface LevelProgress {
  currentLevel: number;
  experiencePoints: number;
  nextLevel: number;
}

interface GameData {
  game: string;
  playtime: Playtime;
  achievements: Achievement[];
  levelProgress: LevelProgress;
}

export default function Widget() {
  const gameData = response.data as GameData;
  const { game, playtime, achievements, levelProgress } = gameData;
  const { theme, primaryColor, accentColor } = response.meta;

  const progressPercentage = (levelProgress.experiencePoints / levelProgress.nextLevel) * 100;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: theme === 'dark' ? '#303030' : '#FFFFFF',
        color: theme === 'dark' ? '#FFFFFF' : '#000000',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              {game}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Total Playtime: {playtime.totalHours} hours
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Last Session: {playtime.lastSession}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Average Session: {playtime.averageSession} hours
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={500}>
              Achievements
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {achievements.map((achievement) => (
                <Chip
                  key={achievement.name}
                  label={achievement.name}
                  color={achievement.unlocked ? 'primary' : 'default'}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={500}>
              Level Progress
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Level {levelProgress.currentLevel}
            </Typography>
            <LinearProgress
              variant="determinate"
              value={progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#F3E8FF',
                '& .MuiLinearProgress-bar': {
                  bgcolor: accentColor,
                  borderRadius: 4,
                },
                mt: 1,
              }}
            />
            <Stack direction="row" justifyContent="space-between" sx={{ mt: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                {levelProgress.experiencePoints} XP
              </Typography>
              <Typography variant="caption" color="text.secondary">
                {levelProgress.nextLevel} XP to next level
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
